const int joy1X = A0;
const int joy1Y = A1;
const int joy2X = A2;
const int joy2Y = A3;

void setup() {
  Serial.begin(9600);
}

void loop() {
  int x1 = analogRead(joy1X);
  int y1 = analogRead(joy1Y);
  int x2 = analogRead(joy2X);
  int y2 = analogRead(joy2Y);

  Serial.print(x1);
  Serial.print(",");
  Serial.print(y1);
  Serial.print(",");
  Serial.print(x2);
  Serial.print(",");
  Serial.println(y2);

  delay(20);
}
